form:Form.form:Scripts:
		function ClearEmpresa()
{
	Ctrl("oi_empresa").SetCValue("");                     
	ClearPuesto();
}
function OnLoad()
{                              
	if  (Ctrl("Estado").GetXValue()=="Sin Errores") 
	{ 	CtrlEnabled("btn_logTCO",false	);          }
	else
	{ 	CtrlEnabled("btn_logTCO",true);              }
}
function ClearPuesto()
{                     
	Ctrl("oi_puesto").SetCValue("");
	ClearPosicion();
}

function ClearPosicion()
{                     
	Ctrl("oi_posicion").SetCValue("");
}



function EJECUTAR_CLICK()
{                             
	if (Ctrl("oi_empresa").GetXValue()=="") { alert("La Empresa es Requerida."); return false; }      
	if (Ctrl("oi_aniomes").GetXValue()=="") { alert("Mes/Año es Requerido."); return false; }

	if (!Ctrl("main").Validate()) return false;

	var mdx = " with ";
/*
mdx += " member [Measures].[Total Costos] as 'Sum({[Measures].[TotContribucion], [Measures].[TotSujetoReten], [Measures].[TotNoSujetoReten]})'  "; 
mdx += "  member [Measures].[TotalGral] as 'Sum({[Estructura].[Todo las Estructuras]}, [Measures].[Total Costos])' "; 
mdx += "  member [Measures].[Sueldo Bruto] as 'Sum({[Measures].[TotSujetoReten], [Measures].[TotNoSujetoReten]})' "; 
mdx += "  member [Measures].[Contribuciones] as '[Measures].[TotContribucion]' "; 
mdx += "  member [Measures].[%] as '([Measures].[Total Costos] / [Measures].[TotalGral])', FORMAT_STRING = '#%'    ";       
mdx += "  member [Measures].[Dif] as '([Measures].[TotalGral] - [Measures].[Presupuesto])' "; 
mdx += "  member [Measures].[Variacion] as '([Measures].[Dif] / [Measures].[Presupuesto])', FORMAT_STRING =  '#%'    ";       
mdx += "select NON EMPTY {[Measures].[Total Costos], [Measures].[Presupuesto], [Measures].[Dif], [Measures].[Variacion]} ON COLUMNS, "; 
mdx += "  NON EMPTY Hierarchize(Union({[Centros de Costo].[Todos los CC]}, [Centros de Costo].[Todos los CC].Children)) ON ROWS "; 

 */

mdx += "  member [Measures].[Total Costos] as 'Sum({[Measures].[TotContribucion], [Measures].[TotSujetoReten], [Measures].[TotNoSujetoReten]})' "; 
mdx += "   member [Measures].[TotalGral] as 'Sum({[Estructura].[Todo las Estructuras]}, [Measures].[Total Costos])'  "; 
mdx += "   member [Measures].[Sueldo Bruto] as 'Sum({[Measures].[TotSujetoReten], [Measures].[TotNoSujetoReten]})'    "; 
mdx += "   member [Measures].[Contribuciones] as '[Measures].[TotContribucion]'    "; 
mdx += "   member [Measures].[Di] as '([Measures].[TotalGral] - [Measures].[Presupuesto])' "; 
mdx += "   member [Measures].[Dif] as '([Measures].[Di])',  "; 
mdx += " FORMAT_STRING = '####0.00' "; 
mdx += "   member [Measures].[Variacion] as '([Measures].[Dif] / [Measures].[Presupuesto])',  "; 
mdx += " FORMAT_STRING =IIf(([Measures].[Di] < 0.0), '|00.0#%|style=green', IIf(([Measures].[Di] = 0.0), '00.0#%',  "; 
mdx += " IIf(([Measures].[Di] < 290.0), '|00.0#%|style=yellow', '|00.0#%|style=red'))) "; 
mdx += " select NON EMPTY {[Measures].[Total Costos], [Measures].[Presupuesto], [Measures].[Dif], [Measures].[Variacion]} ON COLUMNS, "; 
mdx += "   NON EMPTY Hierarchize(Union({[Centros de Costo].[Todos los CC]}, [Centros de Costo].[Todos los CC].Children)) ON ROWS    "; 







	mdx += " from [SUELDOS]  ";

	var where = "";
	if(Ctrl("oi_aniomes").GetCValue()!="")
		where += "[Tiempo].[" + Ctrl("oi_aniomes").GetCValue().split("/")[1] + "].[" + Ctrl("oi_aniomes").GetCValue() + "],";

	if(Ctrl("oi_empresa").GetText(1)!="")
		where += "[Empresas].[" + Ctrl("oi_empresa").GetText(1) + "],";


	if(where!="")
	{                   
		mdx += "where {(" + where.substr(0, where.length-1) + ")}";
	}






	Ctrl("mdx").SetXValue(mdx);

	Ctrl("main").DoEvent("EJECUTAR_CLICK");
	return true;
}

function showLogTCO()
{
	openNewFlowWait("NucleusRH.Base.Indicadores.logTCO.flow","initialize","<param modulo=\"Sueldos\" />",new ObjtectResult(),"L");
}

function ObjtectResult()
{        
	this.processResult= function(xmlin){}
}
